import{c as n,Q as a,j as s,m as o}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"存储(上):Region 与 Anvil 文件格式逐字节","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/07-存储上-Region与Anvil文件格式逐字节.md","filePath":"minecraftLearning/07-存储上-Region与Anvil文件格式逐字节.md","lastUpdated":1781674740000}'),e={name:"minecraftLearning/07-存储上-Region与Anvil文件格式逐字节.md"};function i(r,t,l,p,c,d){return a(),s("div",null,[...t[0]||(t[0]=[o(`<h1 id="存储-上-region-与-anvil-文件格式逐字节" tabindex="-1">存储(上):Region 与 Anvil 文件格式逐字节 <a class="header-anchor" href="#存储-上-region-与-anvil-文件格式逐字节" aria-label="Permalink to &quot;存储(上):Region 与 Anvil 文件格式逐字节&quot;">​</a></h1><p>Minecraft 的世界是&quot;无限&quot;的。你可以朝一个方向一直走,地形永远在你面前生成,从不重复也从不停下。这就引出一个让很多人第一次听到时会愣一下的问题:<strong>一个无限大的世界,凭什么没把你的硬盘撑爆?</strong></p><p>答案分两半。一半是&quot;很多东西根本不存&quot;——这是上一层(地形生成)的事;另一半是&quot;要存的那部分,用一种非常讲究的文件格式存&quot;——这就是本篇要逐字节拆开的 <strong>Region / Anvil 格式</strong>。</p><blockquote><p>一句话先记住:<strong>地形不存,靠种子+噪声现算;只有被玩家改动过的区块才落盘,而且不是一个区块一个文件,而是 1024 个区块打包进一个对齐到 4KB 扇区、带两张索引头表的 <code>.mca</code> 文件。</strong></p></blockquote><hr><h2 id="一、为什么无限世界不撑爆硬盘" tabindex="-1">一、为什么无限世界不撑爆硬盘 <a class="header-anchor" href="#一、为什么无限世界不撑爆硬盘" aria-label="Permalink to &quot;一、为什么无限世界不撑爆硬盘&quot;">​</a></h2><p>回到生成那一层的核心结论:<strong>地形由&quot;种子 + 噪声函数&quot;确定性生成</strong>。同一个种子、同一个坐标,噪声函数永远输出同一个值,所以地形不需要存——走到哪、算到哪。</p><p>这带来一个关键推论:</p><blockquote><p>磁盘上<strong>只存玩家访问过、且被修改过的区块(chunk)</strong>。没去过的地方不占一个字节;去过但没动过的(理论上)也能靠重新生成还原,实际为了加载速度会缓存下来,但本质上&quot;可被算出来的数据不需要持久化&quot;。</p></blockquote><p>所以&quot;无限世界&quot;占用的磁盘,正比于<strong>你实际探索并改动过的范围</strong>,而不是世界的理论大小。一个玩了几百小时的存档可能也就几个 GB,而不是无穷大。这是 Minecraft 存储设计的第一性原理,后面所有格式细节都是为它服务的。</p><hr><h2 id="二、为什么要打包成-region-文件" tabindex="-1">二、为什么要打包成 Region 文件 <a class="header-anchor" href="#二、为什么要打包成-region-文件" aria-label="Permalink to &quot;二、为什么要打包成 Region 文件&quot;">​</a></h2><p>确定了&quot;只存改过的 chunk&quot;,下一个问题是:<strong>这些 chunk 怎么落到文件系统上?</strong></p><p>最朴素的想法是&quot;一个 chunk 一个文件&quot;。这个方案会立刻撞墙:</p><ul><li>一个稍微探索过的世界,轻松有<strong>几百万个 chunk</strong>。</li><li>几百万个小文件意味着几百万个 inode、巨大的目录项;文件系统遍历、备份、删除全部被拖到地上爬。</li><li>每个文件还有&quot;块大小向上取整&quot;的浪费(一个几百字节的 chunk 占满一个 4KB 文件系统块)。</li></ul><p>所以 Minecraft 的选择是<strong>打包</strong>:把一片区域的 chunk 塞进<strong>一个大文件</strong>,文件内部自己做索引和空间管理。这个大文件就是 <strong>Region 文件</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一个 Region = 32 × 32 = 1024 个 chunk</span></span>
<span class="line"><span>文件路径:    world/region/r.&lt;regionX&gt;.&lt;regionZ&gt;.mca</span></span>
<span class="line"><span>其中 regionX = chunkX &gt;&gt; 5,  regionZ = chunkZ &gt;&gt; 5</span></span></code></pre></div><p>也就是说,chunk 坐标右移 5 位(除以 32)就得到它所属的 region 坐标;一个 region 文件管辖 512×512 个方块的水平范围。</p><h3 id="mcregion-→-anvil-的演进" tabindex="-1">McRegion → Anvil 的演进 <a class="header-anchor" href="#mcregion-→-anvil-的演进" aria-label="Permalink to &quot;McRegion → Anvil 的演进&quot;">​</a></h3><ul><li><strong>McRegion</strong>(<code>.mcr</code>):最早的打包格式,奠定了&quot;region 文件 + 扇区 + 索引头&quot;这套结构。</li><li><strong>Anvil</strong>(<code>.mca</code>):现行格式,是 McRegion 的升级版。主要改进是<strong>把 chunk 纵向切成 16³ 的 section 存储</strong>,空 section 不占空间——这正是后来世界高度能扩展到 384 格(1.18)而存储开销可控的基础。</li></ul><p>本篇讲的字节布局以 <strong>Anvil(.mca)</strong> 为准。</p><hr><h2 id="三、-mca-文件逐字节拆解" tabindex="-1">三、.mca 文件逐字节拆解 <a class="header-anchor" href="#三、-mca-文件逐字节拆解" aria-label="Permalink to &quot;三、.mca 文件逐字节拆解&quot;">​</a></h2><p>整个文件的宏观结构只有两部分:<strong>8KB 的头部</strong> + <strong>若干 4KB 的数据扇区</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 扇区 0 (0 ~ 4095):    Location table 位置表   │  4096 字节</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 扇区 1 (4096 ~ 8191): Timestamp table 时间戳表 │  4096 字节</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 扇区 2 起 (8192 ~):   chunk 数据区(按扇区对齐)│  N × 4096 字节</span></span>
<span class="line"><span>│   ...                                          │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>扇区(sector)是这个文件的最小分配单位,固定 4096 字节。</strong> 所有 chunk 数据都按扇区对齐存放,这让&quot;用 3 字节记一个偏移&quot;成为可能(见下)。</p><h3 id="头部-1-location-table-位置表-偏移-0-共-4096-字节" tabindex="-1">头部 1:Location table(位置表,偏移 0,共 4096 字节) <a class="header-anchor" href="#头部-1-location-table-位置表-偏移-0-共-4096-字节" aria-label="Permalink to &quot;头部 1:Location table(位置表,偏移 0,共 4096 字节)&quot;">​</a></h3><p>1024 个条目,每个 <strong>4 字节</strong>,一一对应 region 内 1024 个 chunk 的局部坐标。索引公式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>index = (chunkX &amp; 31) + (chunkZ &amp; 31) * 32</span></span>
<span class="line"><span>字节偏移 = index * 4</span></span></code></pre></div><p>每个 4 字节条目的布局:</p><table tabindex="0"><thead><tr><th>字段</th><th>字节数</th><th>含义</th></tr></thead><tbody><tr><td>offset</td><td>3 字节(大端)</td><td>该 chunk 数据从文件第几个<strong>扇区</strong>开始</td></tr><tr><td>sectorCount</td><td>1 字节</td><td>该 chunk 数据占用几个<strong>扇区</strong></td></tr></tbody></table><p>要点:</p><ul><li><strong>offset 以扇区为单位</strong>,不是字节。offset=2 表示数据从字节 <code>2 × 4096 = 8192</code> 开始(因为扇区 0、1 被两张头表占了,数据最早从扇区 2 起)。</li><li><code>offset = 0 且 sectorCount = 0</code> → 这个 chunk <strong>尚未生成或尚未保存</strong>,直接当不存在处理。</li><li>sectorCount 只有 1 字节,所以单个 chunk 最多 <strong>255 个扇区 ≈ 1020 KB ≈ 1 MB</strong>。超过怎么办?见第五节。</li></ul><h3 id="头部-2-timestamp-table-时间戳表-偏移-4096-共-4096-字节" tabindex="-1">头部 2:Timestamp table(时间戳表,偏移 4096,共 4096 字节) <a class="header-anchor" href="#头部-2-timestamp-table-时间戳表-偏移-4096-共-4096-字节" aria-label="Permalink to &quot;头部 2:Timestamp table(时间戳表,偏移 4096,共 4096 字节)&quot;">​</a></h3><p>同样 1024 个条目,每个 <strong>4 字节</strong>(大端整数),记录对应 chunk <strong>最后一次写入的 Unix 时间戳(秒)</strong>。索引方式和位置表完全一致。</p><p>这张表主要用于增量备份、调试和工具判断&quot;哪些 chunk 最近被动过&quot;。</p><h3 id="数据扇区-偏移-8192-起" tabindex="-1">数据扇区(偏移 8192 起) <a class="header-anchor" href="#数据扇区-偏移-8192-起" aria-label="Permalink to &quot;数据扇区(偏移 8192 起)&quot;">​</a></h3><p>知道了某个 chunk 的 offset,seek 到 <code>offset × 4096</code>,你看到的不是裸数据,而是这样一个小头:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┬──────────────────┬───────────────────────────┐</span></span>
<span class="line"><span>│ length (4字节)│ compression(1字节)│ 压缩后的 chunk 数据 (length-1)│</span></span>
<span class="line"><span>└──────────────┴──────────────────┴───────────────────────────┘</span></span></code></pre></div><ul><li><strong>length(4 字节,大端)</strong>:后续数据的长度(<strong>包含</strong>那 1 字节压缩类型,所以实际压缩数据是 <code>length - 1</code> 字节)。</li><li><strong>compression type(1 字节)</strong>:</li></ul><table tabindex="0"><thead><tr><th>值</th><th>压缩方式</th><th>说明</th></tr></thead><tbody><tr><td>1</td><td>GZip</td><td>历史遗留,几乎不用</td></tr><tr><td>2</td><td><strong>Zlib / deflate</strong></td><td><strong>默认</strong></td></tr><tr><td>3</td><td>不压缩</td><td>极少见</td></tr><tr><td>4</td><td>LZ4</td><td>较新版本可选,解压更快,牺牲压缩率换 CPU</td></tr></tbody></table><p>读一个 chunk 的完整流程因此是:<strong>查位置表 → seek 到扇区 → 读 length → 读压缩类型 → 读出 <code>length-1</code> 字节 → 解压 → 得到 chunk 的 NBT 树</strong>(NBT 与里面的 Palette 是下一篇的主题)。</p><hr><h2 id="四、ascii-总览-一次-chunk-读取" tabindex="-1">四、ASCII 总览:一次 chunk 读取 <a class="header-anchor" href="#四、ascii-总览-一次-chunk-读取" aria-label="Permalink to &quot;四、ASCII 总览:一次 chunk 读取&quot;">​</a></h2><p>把上面三段串成一张图,直观感受&quot;从坐标到字节&quot;的全过程:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chunk (x=35, z=12)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ region 坐标:  (35&gt;&gt;5, 12&gt;&gt;5) = (1, 0)  →  打开 r.1.0.mca</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ 局部索引:     (35&amp;31)+(12&amp;31)*32 = 3 + 12*32 = 387</span></span>
<span class="line"><span>        │                位置表字节偏移 = 387*4 = 1548</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ 读 4 字节:    offset=Sektor号, sectorCount=占几扇区</span></span>
<span class="line"><span>        │                例如 offset=2,sectorCount=1</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ seek 到 2*4096 = 8192</span></span>
<span class="line"><span>        │   ┌─ length      = 0x00000A31  (=2609)</span></span>
<span class="line"><span>        │   ├─ compression = 2 (zlib)</span></span>
<span class="line"><span>        │   └─ payload      = 2608 字节 zlib 数据</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        └─ zlib 解压 → chunk 的 NBT 根标签</span></span></code></pre></div><hr><h2 id="五、踩坑与反直觉点" tabindex="-1">五、踩坑与反直觉点 <a class="header-anchor" href="#五、踩坑与反直觉点" aria-label="Permalink to &quot;五、踩坑与反直觉点&quot;">​</a></h2><h3 id="_1-单-chunk-上限-1mb-超了就外置" tabindex="-1">1. 单 chunk 上限 1MB,超了就外置 <a class="header-anchor" href="#_1-单-chunk-上限-1mb-超了就外置" aria-label="Permalink to &quot;1. 单 chunk 上限 1MB,超了就外置&quot;">​</a></h3><p>sectorCount 只有 1 字节(最多 255 扇区),所以一个 chunk 在 region 文件内最多占约 1MB。极端情况(比如一个塞满了海量物品的箱子群、或巨型方块实体数据)会超过这个上限。</p><p>处理方式:<strong>当压缩类型字节的最高位被置 1</strong>(例如 <code>0x82</code> = <code>0x80 | 2</code>),表示这是一个<strong>超大 chunk</strong>,真实数据不在本 region 文件里,而存到一个外置文件:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>world/region/c.&lt;chunkX&gt;.&lt;chunkZ&gt;.mcc</span></span></code></pre></div><p>region 文件内对应位置只留一个占位。解析时看到最高位置 1,就转去读 <code>.mcc</code>。</p><h3 id="_2-写盘不是-原地改-而是-找空位重排" tabindex="-1">2. 写盘不是&quot;原地改&quot;,而是&quot;找空位重排&quot; <a class="header-anchor" href="#_2-写盘不是-原地改-而是-找空位重排" aria-label="Permalink to &quot;2. 写盘不是&quot;原地改&quot;,而是&quot;找空位重排&quot;&quot;">​</a></h3><p>一个 chunk 被改动后体积可能变大,原来占 1 个扇区现在要占 2 个,原位置塞不下了。此时存档逻辑会在文件里<strong>寻找一段连续的空闲扇区</strong>重新落位,然后更新位置表里的 offset 和 sectorCount。</p><p>后果是:长期增删探索会让 region 文件内部产生<strong>碎片</strong>(空洞夹在已用扇区之间)。这就是为什么有 <strong>MCA Selector</strong> 这类工具提供&quot;优化 / 碎片整理&quot;功能——本质是把扇区重新紧凑排布、回收空洞。</p><h3 id="_3-region-文件常常-看起来很大但很空" tabindex="-1">3. region 文件常常&quot;看起来很大但很空&quot; <a class="header-anchor" href="#_3-region-文件常常-看起来很大但很空" aria-label="Permalink to &quot;3. region 文件常常&quot;看起来很大但很空&quot;&quot;">​</a></h3><p>因为按 4KB 扇区对齐分配,一个只改了几个方块的 chunk 也至少占 1 个扇区(4KB);加上 8KB 头部,一个只探索了边角的 region 文件也有几十 KB 起步。文件大小<strong>不等于</strong>有效数据量,别被 <code>ls -l</code> 吓到。</p><h3 id="_4-别手撸-原子写-——存档损坏多半来自这里" tabindex="-1">4. 别手撸&quot;原子写&quot;——存档损坏多半来自这里 <a class="header-anchor" href="#_4-别手撸-原子写-——存档损坏多半来自这里" aria-label="Permalink to &quot;4. 别手撸&quot;原子写&quot;——存档损坏多半来自这里&quot;">​</a></h3><p>位置表、数据扇区、时间戳表三者必须保持一致。如果写到一半进程被杀(掉电、强杀),可能出现位置表指向一个没写完的扇区,导致 chunk 损坏(经典的 &quot;corrupted chunk&quot;)。这也是为什么直接拷贝正在运行的存档很危险——务必先停服或让世界保存完成。</p><hr><h2 id="六、存档目录里还有什么" tabindex="-1">六、存档目录里还有什么 <a class="header-anchor" href="#六、存档目录里还有什么" aria-label="Permalink to &quot;六、存档目录里还有什么&quot;">​</a></h2><p>Region 文件只是世界数据的主体,一个完整存档目录还包括:</p><table tabindex="0"><thead><tr><th>路径</th><th>内容</th></tr></thead><tbody><tr><td><code>region/</code></td><td>方块、section、方块实体等核心 chunk 数据(本篇主角)</td></tr><tr><td><code>entities/</code></td><td><strong>实体数据</strong>(1.17 起从 chunk 里拆出来,独立 region 格式)</td></tr><tr><td><code>poi/</code></td><td>兴趣点(Point of Interest,村民找工作站/床等用),独立 region 格式</td></tr><tr><td><code>level.dat</code></td><td>世界级元数据(种子、出生点、时间、游戏规则……),GZip 压缩的 NBT</td></tr><tr><td><code>playerdata/&lt;uuid&gt;.dat</code></td><td>每个玩家的背包、坐标、状态(NBT)</td></tr><tr><td><code>data/</code></td><td>地图(<code>map_*.dat</code>)、袭击、刷怪冷却等全局保存数据</td></tr><tr><td><code>DIM-1/</code> <code>DIM1/</code></td><td>下界、末地各自的 region 目录</td></tr></tbody></table><p>注意 <strong>1.17 把实体单独拆到 <code>entities/</code></strong> 这件事:把&quot;方块数据&quot;和&quot;实体数据&quot;分文件,好处是可以在不加载满功能 chunk 的情况下处理实体,也让两类数据各自演进。<code>poi/</code> 同理,是给村民 AI 用的独立索引层。</p><hr><h2 id="七、串联" tabindex="-1">七、串联 <a class="header-anchor" href="#七、串联" aria-label="Permalink to &quot;七、串联&quot;">​</a></h2><p>这一篇是&quot;存储&quot;的上半场,它和系列里几篇紧密咬合:</p><ul><li><strong>承接&quot;地形生成&quot;那一层</strong>:正因为地形能靠<strong>种子 + 噪声确定性算出来</strong>,磁盘才只需要存&quot;改过的 chunk&quot;,Region 格式才有意义——存的是&quot;差异&quot;,不是&quot;全世界&quot;。</li><li><strong>交给下一篇(NBT 与 Palette)</strong>:本篇把 chunk 数据读到了&quot;一坨 zlib 解压后的字节&quot;,但<strong>那坨字节内部是什么结构</strong>——NBT 树、局部调色板、bit-packed 的方块数组——是下半场的主题。区块<strong>内存里的 <code>PalettedContainer</code> 和磁盘上的 palette 几乎同构</strong>,所以加载时近乎零转换,这正是 Minecraft 又快又省的关键一环。</li></ul><p>把两篇连起来看:<strong>Region 文件解决&quot;chunk 这块数据放在硬盘哪里、怎么高效寻址&quot;,NBT/Palette 解决&quot;这块数据内部怎么紧凑表达&quot;。</strong> 一个是外层的寻址与空间管理,一个是内层的结构与压缩,合起来才是 Minecraft 完整的持久化故事。</p>`,70)])])}const g=n(e,[["render",i]]);export{u as __pageData,g as default};
